"use client";
// @ts-nocheck

import { useState, useMemo, useCallback, useRef } from "react";

// ─── STOCK INVENTORY (nominal sizes) ─────────────────────────────────────────
const STOCK = {
  1: [[16,20],[20,20],[20,25],[16,25],[24,24],[14,20],[20,24],[15,20],[12,24],[16,24],[14,25],[10,20],[25,25],[18,25],[16,16],[18,20],[22,22],[10,24],[10,25],[12,25],[15,25],[14,24],[18,24],[20,30]],
  2: [[16,20],[20,20],[20,25],[16,25],[24,24],[12,24],[20,24],[18,24],[18,25],[14,20],[14,25],[16,24],[25,25],[15,20],[10,20],[16,16],[12,20],[18,20],[15,25],[16,30],[20,22],[12,25],[18,18],[20,30]],
  4: [[24,24],[12,24],[20,20],[16,20],[16,25],[20,25],[20,24],[18,24],[16,24]]
};

const PRODUCTS = [
  { id:"aeropleat3",  label:"Camfil Aeropleat 3 MV8",  short:"Aeropleat 3",  merv:8,  drawing:"116306" },
  { id:"3030",        label:"Camfil 30/30 MV8",         short:"30/30",        merv:8,  drawing:"068766" },
  { id:"aeropleat13", label:"Camfil Aeropleat 13 MV8",  short:"Aeropleat 13", merv:13, drawing:"—" },
  { id:"mv8",         label:"Mann Hummel MV8",          short:"MV8",          merv:8,  drawing:"—" },
  { id:"dual9",       label:"Camfil Dual MV9/9A",       short:"Dual MV9/9A",  merv:9,  drawing:"—" },
];

const DEPTH_ACTUAL = { 1: 0.88, 2: 1.75, 4: 3.75 };
const toActual = (nom) => nom - 0.5;
const toActualDepth = (d) => DEPTH_ACTUAL[d];
const PREFERRED = new Set(["16x20","20x20","20x25","16x25","24x24","20x24","12x24","20x30","25x25"]);
const isPreferred = (nomH, nomW) => PREFERRED.has(`${nomH}x${nomW}`) || PREFERRED.has(`${nomW}x${nomH}`);

const LOGO_SRC = "data:image/jpeg;base64,";

// ─── CUTTING ENGINE ──────────────────────────────────────────────────────────
function getStockOrientations(stocks) {
  const orientations = [], seen = new Set();
  for (const [sH, sW] of stocks) {
    const k1 = `${sH},${sW}`;
    if (!seen.has(k1)) { seen.add(k1); orientations.push({ nomH:sH, nomW:sW, actH:toActual(sH), actW:toActual(sW), rotated:false }); }
    if (sH !== sW) {
      const k2 = `${sW},${sH}`;
      if (!seen.has(k2)) { seen.add(k2); orientations.push({ nomH:sW, nomW:sH, actH:toActual(sW), actW:toActual(sH), rotated:true, origNomH:sH, origNomW:sW }); }
    }
  }
  return orientations;
}

function findAllCuts(customH, customW, depth, qty=1) {
  const stocks = STOCK[depth];
  if (!stocks) return null;
  const results = [];
  const allOrientations = getStockOrientations(stocks);
  // Rule: any cut trim must be exactly 0 or ≥ 1" — no slivers under 1" for safety.
  // This applies to ALL cut types including multi-yield edge trims.
  const isSafe = (t) => t === 0 || t >= 1;

  // ── Single cuts ──
  for (const f of allOrientations) {
    if (f.actH >= customH && f.actW >= customW) {
      const trimH = +(f.actH - customH).toFixed(4), trimW = +(f.actW - customW).toFixed(4);
      if (!isSafe(trimH) || !isSafe(trimW)) continue;
      const wasteArea = +((f.actH * f.actW) - (customH * customW)).toFixed(4);
      const cuts = (trimH > 0 ? 1 : 0) + (trimW > 0 ? 1 : 0);
      results.push({ type:"single", layout:"single", gridRows:1, gridCols:1, stockFilters:[{ nomH:f.nomH, nomW:f.nomW, actH:f.actH, actW:f.actW, rotated:f.rotated, origNomH:f.origNomH, origNomW:f.origNomW }], trimH, trimW, wasteArea, cuts, customActH:customH, customActW:customW, depth });
    }
  }

  // ── Multi-yield: max 2 filters per stock, only 2×1 or 1×2, only when qty > 1 ──
  // Middle waste rule: waste/cap goes BETWEEN the two filters (outer edges = stock frame).
  if (qty > 1) {
    for (const f of allOrientations) {
      // 2×1: two filters stacked along height
      {
        const neededH = 2 * customH, neededW = customW;
        if (f.actH >= neededH && f.actW >= neededW) {
          const trimH = +(f.actH - neededH).toFixed(4);
          const trimW = +(f.actW - neededW).toFixed(4);
          if (isSafe(trimH) && isSafe(trimW)) {
            const wasteArea = +((f.actH * f.actW) - (neededH * neededW)).toFixed(4);
            const cuts = 1 + (trimH > 0 ? 1 : 0) + (trimW > 0 ? 1 : 0);
            results.push({ type:"multi-yield-2x1", layout:"multi-yield", yieldAxis:"H", yieldsPerStock:2, gridRows:2, gridCols:1, stockFilters:[{ nomH:f.nomH, nomW:f.nomW, actH:f.actH, actW:f.actW, rotated:f.rotated, origNomH:f.origNomH, origNomW:f.origNomW }], trimH, trimW, wasteArea, cuts, customActH:customH, customActW:customW, depth });
          }
        }
      }
      // 1×2: two filters side by side along width
      {
        const neededH = customH, neededW = 2 * customW;
        if (f.actH >= neededH && f.actW >= neededW) {
          const trimH = +(f.actH - neededH).toFixed(4);
          const trimW = +(f.actW - neededW).toFixed(4);
          if (isSafe(trimH) && isSafe(trimW)) {
            const wasteArea = +((f.actH * f.actW) - (neededH * neededW)).toFixed(4);
            const cuts = 1 + (trimH > 0 ? 1 : 0) + (trimW > 0 ? 1 : 0);
            results.push({ type:"multi-yield-1x2", layout:"multi-yield", yieldAxis:"W", yieldsPerStock:2, gridRows:1, gridCols:2, stockFilters:[{ nomH:f.nomH, nomW:f.nomW, actH:f.actH, actW:f.actW, rotated:f.rotated, origNomH:f.origNomH, origNomW:f.origNomW }], trimH, trimW, wasteArea, cuts, customActH:customH, customActW:customW, depth });
          }
        }
      }
    }
  }

  // ── Linear butt joints ──
  const byActH = {};
  for (const f of allOrientations) { const hKey = f.actH.toFixed(2); if (!byActH[hKey]) byActH[hKey]=[]; byActH[hKey].push(f); }
  const addLinearResult = (actH, filterCombo) => {
    const combinedW = filterCombo.reduce((sum, f) => sum + f.actW, 0);
    if (combinedW < customW) return;
    const trimH = +(actH - customH).toFixed(4), trimW = +(combinedW - customW).toFixed(4);
    if (!isSafe(trimH) || !isSafe(trimW)) return;
    const wasteArea = +((actH * combinedW) - (customH * customW)).toFixed(4);
    const joints = filterCombo.length - 1;
    const cuts = joints + (trimH > 0 ? 1 : 0) + (trimW > 0 ? 1 : 0);
    results.push({ type:`linear-${filterCombo.length}`, layout:"linear", gridRows:1, gridCols:filterCombo.length, stockFilters:filterCombo.map(f=>({ nomH:f.nomH, nomW:f.nomW, actH:f.actH, actW:f.actW, rotated:f.rotated, origNomH:f.origNomH, origNomW:f.origNomW })), trimH, trimW, combinedW, combinedH:actH, wasteArea, cuts, customActH:customH, customActW:customW, depth });
  };
  for (const [hKey, filters] of Object.entries(byActH)) {
    const actH = parseFloat(hKey);
    if (actH < customH) continue;
    for (let i=0;i<filters.length;i++) for (let j=i;j<filters.length;j++) addLinearResult(actH,[filters[i],filters[j]]);
    for (let i=0;i<filters.length;i++) for (let j=i;j<filters.length;j++) for (let k=j;k<filters.length;k++) addLinearResult(actH,[filters[i],filters[j],filters[k]]);
    for (let i=0;i<filters.length;i++) for (let j=i;j<filters.length;j++) for (let k=j;k<filters.length;k++) for (let l=k;l<filters.length;l++) addLinearResult(actH,[filters[i],filters[j],filters[k],filters[l]]);
  }

  // ── Grid butt joints ──
  const uniqueHeights = [...new Set(allOrientations.map(f => +f.actH.toFixed(2)))].sort((a,b)=>a-b);
  const uniqueWidths  = [...new Set(allOrientations.map(f => +f.actW.toFixed(2)))].sort((a,b)=>a-b);
  const findFilter = (h, w) => allOrientations.find(f => +f.actH.toFixed(2) === +h.toFixed(2) && +f.actW.toFixed(2) === +w.toFixed(2));
  const addGridResult = (rowHeights, colWidths) => {
    const nRows=rowHeights.length, nCols=colWidths.length;
    const combinedH=rowHeights.reduce((a,b)=>a+b,0), combinedW=colWidths.reduce((a,b)=>a+b,0);
    if (combinedH<customH||combinedW<customW) return;
    const trimH=+(combinedH-customH).toFixed(4), trimW=+(combinedW-customW).toFixed(4);
    if (!isSafe(trimH)||!isSafe(trimW)) return;
    const gridFilters=[];
    for (let r=0;r<nRows;r++) for (let c=0;c<nCols;c++) { const f=findFilter(rowHeights[r],colWidths[c]); if (!f) return; gridFilters.push({ nomH:f.nomH, nomW:f.nomW, actH:f.actH, actW:f.actW, rotated:f.rotated, origNomH:f.origNomH, origNomW:f.origNomW, gridRow:r, gridCol:c }); }
    const wasteArea=+((combinedH*combinedW)-(customH*customW)).toFixed(4);
    const joints=(nRows-1)+(nCols-1), cuts=joints+(trimH>0?1:0)+(trimW>0?1:0);
    results.push({ type:`grid-${nRows}x${nCols}`, layout:"grid", gridRows:nRows, gridCols:nCols, rowHeights, colWidths, stockFilters:gridFilters, trimH, trimW, combinedW, combinedH, wasteArea, cuts, customActH:customH, customActW:customW, depth });
  };
  const gridConfigs=[[2,2],[2,3],[3,2]];
  for (const [nRows,nCols] of gridConfigs) {
    const hCombos=nRows===2?uniqueHeights.flatMap((h1,i)=>uniqueHeights.slice(i).map(h2=>[h1,h2])):uniqueHeights.flatMap((h1,i)=>uniqueHeights.slice(i).flatMap((h2,j)=>uniqueHeights.slice(i+j).map(h3=>[h1,h2,h3])));
    const wCombos=nCols===2?uniqueWidths.flatMap((w1,i)=>uniqueWidths.slice(i).map(w2=>[w1,w2])):uniqueWidths.flatMap((w1,i)=>uniqueWidths.slice(i).flatMap((w2,j)=>uniqueWidths.slice(i+j).map(w3=>[w1,w2,w3])));
    for (const rh of hCombos) { const totalH=rh.reduce((a,b)=>a+b,0); if(totalH<customH) continue; for (const cw of wCombos) { const totalW=cw.reduce((a,b)=>a+b,0); if(totalW<customW) continue; addGridResult(rh,cw); } }
  }

  // ── SORT PRIORITY ──────────────────────────────────────────────────────────
  // Rule 1: Preferred stock sizes FIRST within every tier (we stock more of these)
  // Rule 2: Multi-yield ALWAYS before standard cuts when qty > 1
  // Within each tier: preferred stock → least waste → fewer cuts
  const prefScore = (r) => {
    const allPref = r.stockFilters.every(f => isPreferred(f.nomH, f.nomW));
    const somePref = r.stockFilters.some(f => isPreferred(f.nomH, f.nomW));
    return allPref ? 0 : somePref ? 1 : 2;
  };
  results.sort((a, b) => {
    const aIsMulti = a.layout === "multi-yield" ? 1 : 0;
    const bIsMulti = b.layout === "multi-yield" ? 1 : 0;
    // Tier 1: Multi-yield always before standard cuts
    if (aIsMulti !== bIsMulti) return bIsMulti - aIsMulti;
    // Within same tier: preferred stock is #1 tiebreaker
    const prefDiff = prefScore(a) - prefScore(b);
    if (prefDiff !== 0) return prefDiff;
    // Then: least waste area
    const wasteDiff = a.wasteArea - b.wasteArea;
    if (wasteDiff !== 0) return wasteDiff;
    // Then: fewest stock filters
    const countDiff = a.stockFilters.length - b.stockFilters.length;
    if (countDiff !== 0) return countDiff;
    // Finally: fewer cuts
    return a.cuts - b.cuts;
  });
  return results.length > 0 ? results.slice(0, 10) : null;
}

// ─── SVG CUT DIAGRAM (always B&W for consistency with manufacturing sheets) ─
function CutDiagram({ result, compact = false }) {
  const svgW = compact ? 320 : 420, svgH = compact ? 220 : 300, pad = compact ? 40 : 55;
  const drawW = svgW - pad * 2, drawH = svgH - pad * 2;
  const stockFill = "#e8e8e8", stockStroke = "#111";
  const keepFill = "#ddd", keepFillOp = 0.9;
  const keepStroke = "#111";
  const wasteFill = "#fff", wasteFillOp = 0, wasteStroke = "#555";
  const dimStroke = "#111", dimFill = "#111";
  const stkDimStroke = "#555", stkDimFill = "#555";
  const keepTextFill = "#000", wasteTextFill = "#444";
  const jointStroke = "#333", jointTextFill = "#333";
  const filterColors = ["#bbb","#999","#777","#555","#888","#aaa"];
  const labelColors = ["#222","#333","#444","#555","#666","#777"];
  const fontSize = compact ? 9 : 11;
  const svgBg = "#fff";

  // Multi-yield: show FILTER 1 → middle cap/waste → FILTER 2 (outer edges = stock frame)
  if (result.layout === "multi-yield") {
    const f = result.stockFilters[0];
    const scale = Math.min(drawW / f.actW, drawH / f.actH);
    const rw = f.actW * scale, rh = f.actH * scale;
    const ox = (svgW - rw) / 2, oy = (svgH - rh) / 2;
    const cw = result.customActW * scale, ch = result.customActH * scale;
    const capColor = "#555";
    const capFillOp = 0.3;

    if (result.yieldAxis === "H") {
      // 2×1 stacked: [Filter 1 top] [cap/waste middle] [Filter 2 bottom] | [side trim right]
      const capH = result.trimH * scale;
      const sideTrimW = result.trimW * scale;
      return (
        <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width:"100%", maxHeight:svgH, background:svgBg }}>
          <rect x={ox} y={oy} width={rw} height={rh} fill={stockFill} stroke={stockStroke} strokeWidth={1.5} rx={2}/>
          <rect x={ox} y={oy} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={1}/>
          <text x={ox+cw/2} y={oy+ch/2} textAnchor="middle" dominantBaseline="middle" fill={keepTextFill} fontSize={compact?9:11} fontWeight="bold" fontFamily="monospace">FILTER 1</text>
          {capH>0&&<><rect x={ox} y={oy+ch} width={cw} height={capH} fill={capColor} fillOpacity={capFillOp} stroke={capColor} strokeWidth={1.5} strokeDasharray="4 2"/>
          <text x={ox+cw/2} y={oy+ch+capH/2} textAnchor="middle" dominantBaseline="middle" fill={capColor} fontSize={compact?7:9} fontWeight="bold" fontFamily="monospace">{result.trimH}" cap</text></>}
          <rect x={ox} y={oy+ch+capH} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={1}/>
          <text x={ox+cw/2} y={oy+ch+capH+ch/2} textAnchor="middle" dominantBaseline="middle" fill={keepTextFill} fontSize={compact?9:11} fontWeight="bold" fontFamily="monospace">FILTER 2</text>
          {sideTrimW>0&&<rect x={ox+cw} y={oy} width={sideTrimW} height={rh} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
          <text x={ox+rw/2} y={oy-8} textAnchor="middle" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace">{f.actW}" stock</text>
          <text x={ox-6} y={oy+rh/2} textAnchor="end" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace" dominantBaseline="middle">{f.actH}"</text>
          <line x1={ox+rw+8} y1={oy} x2={ox+rw+8} y2={oy+ch} stroke={dimStroke} strokeWidth={1}/><text x={ox+rw+12} y={oy+ch/2} textAnchor="start" fill={dimFill} fontSize={fontSize-1} fontFamily="monospace" dominantBaseline="middle">{result.customActH}"</text>
          <line x1={ox} y1={oy+rh+8} x2={ox+cw} y2={oy+rh+8} stroke={dimStroke} strokeWidth={1}/><text x={ox+cw/2} y={oy+rh+18} textAnchor="middle" fill={dimFill} fontSize={fontSize-1} fontFamily="monospace">{result.customActW}"</text>
        </svg>
      );
    } else {
      // 1×2 side by side: [Filter 1 left] [cap/waste middle] [Filter 2 right] | [side trim bottom]
      const capW = result.trimW * scale;
      const sideTrimH = result.trimH * scale;
      return (
        <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width:"100%", maxHeight:svgH, background:svgBg }}>
          <rect x={ox} y={oy} width={rw} height={rh} fill={stockFill} stroke={stockStroke} strokeWidth={1.5} rx={2}/>
          <rect x={ox} y={oy} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={1}/>
          <text x={ox+cw/2} y={oy+ch/2} textAnchor="middle" dominantBaseline="middle" fill={keepTextFill} fontSize={compact?9:11} fontWeight="bold" fontFamily="monospace">FILTER 1</text>
          {capW>0&&<><rect x={ox+cw} y={oy} width={capW} height={ch} fill={capColor} fillOpacity={capFillOp} stroke={capColor} strokeWidth={1.5} strokeDasharray="4 2"/>
          <text x={ox+cw+capW/2} y={oy+ch/2} textAnchor="middle" dominantBaseline="middle" fill={capColor} fontSize={compact?7:9} fontWeight="bold" fontFamily="monospace">{result.trimW}" cap</text></>}
          <rect x={ox+cw+capW} y={oy} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={1}/>
          <text x={ox+cw+capW+cw/2} y={oy+ch/2} textAnchor="middle" dominantBaseline="middle" fill={keepTextFill} fontSize={compact?9:11} fontWeight="bold" fontFamily="monospace">FILTER 2</text>
          {sideTrimH>0&&<rect x={ox} y={oy+ch} width={rw} height={sideTrimH} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
          <text x={ox+rw/2} y={oy-8} textAnchor="middle" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace">{f.actW}" stock</text>
          <text x={ox-6} y={oy+rh/2} textAnchor="end" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace" dominantBaseline="middle">{f.actH}"</text>
          <line x1={ox} y1={oy+rh+8} x2={ox+cw} y2={oy+rh+8} stroke={dimStroke} strokeWidth={1}/><text x={ox+cw/2} y={oy+rh+18} textAnchor="middle" fill={dimFill} fontSize={fontSize-1} fontFamily="monospace">{result.customActW}"</text>
        </svg>
      );
    }
  }

  if (result.type === "single") {
    const f = result.stockFilters[0];
    const scale = Math.min(drawW / f.actW, drawH / f.actH);
    const rw = f.actW * scale, rh = f.actH * scale;
    const ox = (svgW - rw) / 2, oy = (svgH - rh) / 2;
    const cw = result.customActW * scale, ch = result.customActH * scale;
    return (
      <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width:"100%", maxHeight:svgH, background:svgBg }}>
        <rect x={ox} y={oy} width={rw} height={rh} fill={stockFill} stroke={stockStroke} strokeWidth={1.5} rx={2}/>
        <rect x={ox} y={oy} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={2}/>
        {result.trimW>0&&<rect x={ox+cw} y={oy} width={rw-cw} height={ch} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
        {result.trimH>0&&<rect x={ox} y={oy+ch} width={rw} height={rh-ch} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
        <line x1={ox} y1={oy-10} x2={ox+cw} y2={oy-10} stroke={dimStroke} strokeWidth={1}/><text x={ox+cw/2} y={oy-15} textAnchor="middle" fill={dimFill} fontSize={fontSize} fontFamily="monospace">{result.customActW}"</text>
        <line x1={ox} y1={oy-24} x2={ox+rw} y2={oy-24} stroke={stkDimStroke} strokeWidth={1}/><text x={ox+rw/2} y={oy-29} textAnchor="middle" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace">{f.actW}" stk</text>
        <line x1={ox-10} y1={oy} x2={ox-10} y2={oy+ch} stroke={dimStroke} strokeWidth={1}/><text x={ox-14} y={oy+ch/2} textAnchor="end" fill={dimFill} fontSize={fontSize} fontFamily="monospace" dominantBaseline="middle">{result.customActH}"</text>
        <line x1={ox+rw+10} y1={oy} x2={ox+rw+10} y2={oy+rh} stroke={stkDimStroke} strokeWidth={1}/><text x={ox+rw+14} y={oy+rh/2} textAnchor="start" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace" dominantBaseline="middle">{f.actH}"</text>
        <text x={ox+cw/2} y={oy+ch/2} textAnchor="middle" fill={keepTextFill} fontSize={compact?11:13} fontWeight="bold" fontFamily="monospace" dominantBaseline="middle">KEEP</text>
        {result.trimW>0&&<text x={ox+cw+(rw-cw)/2} y={oy+ch/2} textAnchor="middle" fill={wasteTextFill} fontSize={8} fontFamily="monospace" dominantBaseline="middle">{result.trimW}" waste</text>}
        {result.trimH>0&&<text x={ox+rw/2} y={oy+ch+(rh-ch)/2} textAnchor="middle" fill={wasteTextFill} fontSize={8} fontFamily="monospace" dominantBaseline="middle">{result.trimH}" waste</text>}
      </svg>
    );
  }

  if (result.layout === "grid") {
    const { rowHeights, colWidths, gridRows, gridCols } = result;
    const totalH=rowHeights.reduce((a,b)=>a+b,0), totalW=colWidths.reduce((a,b)=>a+b,0);
    const scale=Math.min(drawW/totalW, drawH/totalH);
    const scaledColW=colWidths.map(w=>w*scale), scaledRowH=rowHeights.map(h=>h*scale);
    const totalRW=scaledColW.reduce((a,b)=>a+b,0), totalRH=scaledRowH.reduce((a,b)=>a+b,0);
    const ox=(svgW-totalRW)/2, oy=(svgH-totalRH)/2;
    const cw=result.customActW*scale, ch=result.customActH*scale;
    const xPos=[]; let cx2=ox; for(const w of scaledColW){xPos.push(cx2);cx2+=w;}
    const yPos=[]; let cy2=oy; for(const h of scaledRowH){yPos.push(cy2);cy2+=h;}
    return (
      <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width:"100%", maxHeight:svgH, background:svgBg }}>
        {result.stockFilters.map((f,i)=><rect key={i} x={xPos[f.gridCol]} y={yPos[f.gridRow]} width={scaledColW[f.gridCol]} height={scaledRowH[f.gridRow]} fill={stockFill} stroke={filterColors[i%filterColors.length]} strokeWidth={1.5} rx={2} strokeDasharray={i>0?"6 3":"none"}/>)}
        <rect x={ox} y={oy} width={cw} height={ch} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={2}/>
        {xPos.slice(1).map((xp,i)=><line key={`v${i}`} x1={xp} y1={oy} x2={xp} y2={oy+totalRH} stroke={jointStroke} strokeWidth={2} strokeDasharray="4 3"/>)}
        {yPos.slice(1).map((yp,i)=><line key={`h${i}`} x1={ox} y1={yp} x2={ox+totalRW} y2={yp} stroke={jointStroke} strokeWidth={2} strokeDasharray="4 3"/>)}
        {result.trimW>0&&<rect x={ox+cw} y={oy} width={totalRW-cw} height={ch} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
        {result.trimH>0&&<rect x={ox} y={oy+ch} width={totalRW} height={totalRH-ch} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
        {result.stockFilters.map((f,i)=><text key={i} x={xPos[f.gridCol]+scaledColW[f.gridCol]/2} y={yPos[f.gridRow]+scaledRowH[f.gridRow]/2} textAnchor="middle" dominantBaseline="middle" fill={labelColors[i%labelColors.length]} fontSize={Math.max(7,Math.min(9,60/Math.max(gridRows,gridCols)))} fontFamily="monospace">{String.fromCharCode(65+i)}: {f.nomH}x{f.nomW}</text>)}
        <line x1={ox} y1={oy-10} x2={ox+cw} y2={oy-10} stroke={dimStroke} strokeWidth={1}/><text x={ox+cw/2} y={oy-15} textAnchor="middle" fill={dimFill} fontSize={fontSize} fontFamily="monospace">{result.customActW}"</text>
        <line x1={ox-10} y1={oy} x2={ox-10} y2={oy+ch} stroke={dimStroke} strokeWidth={1}/><text x={ox-14} y={oy+ch/2} textAnchor="end" fill={dimFill} fontSize={fontSize} fontFamily="monospace" dominantBaseline="middle">{result.customActH}"</text>
        <text x={ox+cw/2} y={oy+ch/2} textAnchor="middle" fill={keepTextFill} fontSize={compact?10:12} fontWeight="bold" fontFamily="monospace" dominantBaseline="middle">KEEP</text>
      </svg>
    );
  }

  // Linear butt
  const filters = result.stockFilters;
  const totalW=filters.reduce((sum,f)=>sum+f.actW,0), maxH=filters[0].actH;
  const scale=Math.min(drawW/totalW, drawH/maxH);
  const scaledWidths=filters.map(f=>f.actW*scale);
  const rh2=maxH*scale, totalRW=scaledWidths.reduce((a,b)=>a+b,0);
  const ox2=(svgW-totalRW)/2, oy2=(svgH-rh2)/2;
  const cw2=result.customActW*scale, ch2=result.customActH*scale;
  const xPositions=[]; let lx=ox2; for(const sw of scaledWidths){xPositions.push(lx);lx+=sw;}
  return (
    <svg viewBox={`0 0 ${svgW} ${svgH}`} style={{ width:"100%", maxHeight:svgH, background:svgBg }}>
      {filters.map((f,i)=><rect key={i} x={xPositions[i]} y={oy2} width={scaledWidths[i]} height={rh2} fill={stockFill} stroke={filterColors[i%filterColors.length]} strokeWidth={1.5} rx={2} strokeDasharray={i>0?"6 3":"none"}/>)}
      <rect x={ox2} y={oy2} width={cw2} height={ch2} fill={keepFill} fillOpacity={keepFillOp} stroke={keepStroke} strokeWidth={2} rx={2}/>
      {xPositions.slice(1).map((xp,i)=><g key={i}><line x1={xp} y1={oy2} x2={xp} y2={oy2+rh2} stroke={jointStroke} strokeWidth={2} strokeDasharray="4 3"/><text x={xp} y={oy2+rh2+12} textAnchor="middle" fill={jointTextFill} fontSize={7} fontFamily="monospace">joint</text></g>)}
      {result.trimW>0&&<rect x={ox2+cw2} y={oy2} width={totalRW-cw2} height={ch2} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
      {result.trimH>0&&<rect x={ox2} y={oy2+ch2} width={totalRW} height={rh2-ch2} fill={wasteFill} fillOpacity={wasteFillOp} stroke={wasteStroke} strokeWidth={1} strokeDasharray="4 2"/>}
      <line x1={ox2} y1={oy2-10} x2={ox2+cw2} y2={oy2-10} stroke={dimStroke} strokeWidth={1}/><text x={ox2+cw2/2} y={oy2-15} textAnchor="middle" fill={dimFill} fontSize={fontSize} fontFamily="monospace">{result.customActW}"</text>
      <line x1={ox2} y1={oy2-24} x2={ox2+totalRW} y2={oy2-24} stroke={stkDimStroke} strokeWidth={1}/><text x={ox2+totalRW/2} y={oy2-29} textAnchor="middle" fill={stkDimFill} fontSize={fontSize-1} fontFamily="monospace">{totalW}" combined</text>
      {filters.map((f,i)=><text key={i} x={xPositions[i]+scaledWidths[i]/2} y={oy2+rh2+24} textAnchor="middle" fill={labelColors[i%labelColors.length]} fontSize={Math.min(9,100/filters.length)} fontFamily="monospace">{String.fromCharCode(65+i)}: {f.nomH}x{f.nomW}</text>)}
      <line x1={ox2-10} y1={oy2} x2={ox2-10} y2={oy2+ch2} stroke={dimStroke} strokeWidth={1}/><text x={ox2-14} y={oy2+ch2/2} textAnchor="end" fill={dimFill} fontSize={fontSize} fontFamily="monospace" dominantBaseline="middle">{result.customActH}"</text>
      <text x={ox2+cw2/2} y={oy2+ch2/2} textAnchor="middle" fill={keepTextFill} fontSize={compact?11:13} fontWeight="bold" fontFamily="monospace" dominantBaseline="middle">KEEP</text>
    </svg>
  );
}

// ─── STOCK SUMMARY HELPER ───────────────────────────────────────────────────
function calcStockSummary(cartItems) {
  const map = {};
  for (const item of cartItems) {
    if (!item.selectedResult) continue;
    const r = item.selectedResult;
    const yieldsPerStock = r.yieldsPerStock || 1;
    const stockNeeded = Math.ceil(item.qty / yieldsPerStock);
    const prod = PRODUCTS.find(p => p.id === item.productId) || PRODUCTS[0];
    for (const sf of r.stockFilters) {
      const nomLabel = sf.rotated ? `${sf.origNomH}x${sf.origNomW}` : `${sf.nomH}x${sf.nomW}`;
      const sizeKey = `${nomLabel} x ${r.depth}"`;
      const key = `${item.productId}||${sizeKey}`;
      if (!map[key]) map[key] = { productId:item.productId, productShort:prod.short, productLabel:prod.label, sizeKey, qty:0 };
      map[key].qty += stockNeeded;
    }
  }
  return Object.values(map).sort((a, b) => a.productLabel.localeCompare(b.productLabel) || a.sizeKey.localeCompare(b.sizeKey));
}

